// Stage: EX/MEM and MEM/WB pipeline registers

CHECK_FORWARDING(executeStage, memStage, wbStage)
BEGIN
 // ALU result from EX/MEM stage to EX stage of dependent instruction
 if (memStage.valid AND memStage.destReg == executeStage.srcReg1) then
 forwardA = MEM/WB.result // Forward from MEM stage
