CALCULATE_BRANCH_CPI(branchFreq, branchPenalty, predictionAccuracy)
// branchFreq: frequency of branch instructions (0-1)
// branchPenalty: cycles lost on misprediction
// predictionAccuracy: branch predictor accuracy (0-1)

BEGIN
 mispredictionRate = 1 - predictionAccuracy
 branchStallsPerInstruction = branchFreq * mispredictionRate * branchPenalty

 effectiveCPI = 1 + branchStallsPerInstruction
 // Ideal CPI = 1 (no hazards)

 speedup = 1 / effectiveCPI

 RETURN effectiveCPI, speedup
END

// Example: branchFreq=0.25, branchPenalty=3, accuracy=0.80
// mispredictionRate = 0.20
// branchStalls = 0.25 × 0.20 × 3 = 0.15
// effectiveCPI = 1.15
// speedup = 1/1.15 = 0.87 (87% of ideal)
